namespace sv_c0c0eb74c95040679292d153f38e3d96.Services;

public sealed class Recipe
{
    public int Id { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public int PrepTimeMinutes { get; init; }
}

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Spaghetti Carbonara", Description = "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Margherita Pizza", Description = "Neapolitan pizza with San Marzano tomatoes, mozzarella, and fresh basil.", PrepTimeMinutes = 45 },
            new() { Id = 3, Title = "Tiramisu", Description = "Layered coffee-soaked ladyfingers with mascarpone cream.", PrepTimeMinutes = 40 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Pad Thai", Description = "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", PrepTimeMinutes = 25 },
            new() { Id = 5, Title = "Green Curry", Description = "Aromatic coconut curry with Thai basil, bamboo shoots, and chicken.", PrepTimeMinutes = 35 },
            new() { Id = 6, Title = "Tom Yum Soup", Description = "Hot and sour soup with lemongrass, galangal, and prawns.", PrepTimeMinutes = 20 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Marinated pork tacos with pineapple, cilantro, and onion.", PrepTimeMinutes = 50 },
            new() { Id = 8, Title = "Guacamole", Description = "Fresh avocado dip with lime, jalapeño, tomato, and cilantro.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Churros", Description = "Fried dough pastries coated in cinnamon sugar, served with chocolate sauce.", PrepTimeMinutes = 30 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@using sv_c0c0eb74c95040679292d153f38e3d96.Services
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

<p>
    <a href="/recipes/1?sort=@_sort">Italian</a> |
    <a href="/recipes/2?sort=@_sort">Thai</a> |
    <a href="/recipes/3?sort=@_sort">Mexican</a>
</p>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in GetSortedRecipes())
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private string _sort = "newest";
    private int _loadedCuisineId;
    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    public override async Task SetParametersAsync(ParameterView parameters)
    {
        var previousCuisineId = CuisineId;

        await base.SetParametersAsync(parameters);

        _sort = string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase) ? "popular" : "newest";

        // Only reload data when the cuisine changes
        if (CuisineId != _loadedCuisineId)
        {
            await LoadRecipesAsync();
        }
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight load
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
        _loadCts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, _loadCts.Token);
            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (_disposeCts.IsCancellationRequested)
        {
            // Component is being disposed — do nothing
        }
        catch (OperationCanceledException)
        {
            // A newer load superseded this one — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    private IEnumerable<Recipe> GetSortedRecipes()
    {
        if (_recipes is null) return Enumerable.Empty<Recipe>();

        return _sort == "popular"
            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
            : _recipes.OrderByDescending(r => r.Id);
    }

    public async ValueTask DisposeAsync()
    {
        await _disposeCts.CancelAsync();
        _disposeCts.Dispose();

        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
        }
    }
}

